     3→import edu.rice.hj.api.SuspendableException;
     4→
     5→/**
     6→ * Sequential Smith-Waterman algorithm adapted for COMP 322 homework.
     7→ */
     8→public class SeqScoring extends AbstractPreallocatedSorting {
     9→
    10→    /**
    11→     * Creates a new SeqScoring.
    12→     *
    13→     * @param xLength length of the first sequence
    14→     * @param yLength length of the second sequence
    15→     */
    16→    public SeqScoring(final int xLength, final int yLength) {
    17→        super(xLength, yLength);
    18→    }
    19→
    20→    /**
    21→     * A reference sequential implementation of the Smith-Waterman alignment algorithm.
    22→     * {@inheritDoc}
    23→     */
    24→    public int scoreSequences(final String x, final String y) throws SuspendableException {
    25→
    26→        final int xLength = getXLength();
    27→        final int yLength = getYLength();
    28→        final int[][] S = getMatrix();
    29→
    30→        for (int i = 1; i <= xLength; i++) {
    31→            for (int j = 1; j <= yLength; j++) {
    32→                // the two characters to be compared
    33→                final char XChar = x.charAt(i - 1);
    34→                final char YChar = y.charAt(j - 1);
    35→
    36→                // find the largest point to jump from, and use it
    37→                final int diagScore = S[i - 1][j - 1] + getScore(charMap(XChar), charMap(YChar));
    38→                final int topColScore = S[i - 1][j] + getScore(charMap(XChar), 0);
    39→                final int leftRowScore = S[i][j - 1] + getScore(0, charMap(YChar));
    40→                S[i][j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
    41→            }
    42→        }
    43→
    44→        // final value in the matrix is the score
    45→        return S[xLength][yLength];
    46→    }
    47→
    48→}
