     3→/**
     4→ * A scoring object that preallocates its matrix.
     5→ *
     6→ * @author Derek Peirce
     7→ */
     8→public abstract class AbstractPreallocatedSorting extends AbstractDnaScoring {
     9→
    10→    /**
    11→     * The length of the first sequence.
    12→     */
    13→    private final int xLength;
    14→    /**
    15→     * The length of the second sequence.
    16→     */
    17→    private final int yLength;
    18→
    19→    /**
    20→     * The Smith-Waterman matrix.
    21→     */
    22→    private final int[][] s;
    23→
    24→    /**
    25→     * Creates a sorting object, allocating all of the memory it will need for the computations.
    26→     *
    27→     * @param xLength length of the first sequence
    28→     * @param yLength length of the second sequence
    29→     */
    30→    public AbstractPreallocatedSorting(final int xLength, final int yLength) {
    31→        this.xLength = xLength;
    32→        this.yLength = yLength;
    33→        //pre allocate the matrix for alignment, dimension+1 for initializations
    34→        s = new int[xLength + 1][yLength + 1];
    35→
    36→        //init row
    37→        for (int ii = 1; ii < xLength + 1; ii++) {
    38→            s[ii][0] = getScore(1, 0) * ii;
    39→        }
    40→
    41→        //init column
    42→        for (int jj = 1; jj < yLength + 1; jj++) {
    43→            s[0][jj] = getScore(0, 1) * jj;
    44→        }
    45→        //init diagonal
    46→        s[0][0] = 0;
    47→    }
    48→
    49→    /**
    50→     * Fetch the length of the first sequence being aligned.
    51→     * @return length of the first sequence
    52→     */
    53→    protected int getXLength() {
    54→        return xLength;
    55→    }
    56→
    57→    /**
    58→     * Fetch the length of the second sequence being aligned.
    59→     * @return length of the second sequence
    60→     */
    61→    protected int getYLength() {
    62→        return yLength;
    63→    }
    64→
    65→    /**
    66→     * The full Smith-Waterman matrix.
    67→     * @return the Smith-Waterman matrix
    68→     */
    69→    protected int[][] getMatrix() {
    70→        return s;
    71→    }
    72→}
    73→

