package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;
import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;
import static edu.rice.hj.Module1.doWork;

/**
 * A scorer that works in parallel with ideal abstract parallelism.
 * Uses anti-diagonal wavefront parallelism to achieve CPL = xLength + yLength - 1.
 */
public class IdealParScoring extends AbstractPreallocatedSorting {

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
        scoringRunner.start("IdealParScoring", args);
    }

    /**
     * Creates a new IdealParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public IdealParScoring(final int xLength, final int yLength) {
        super(xLength, yLength);
    }

    /**
     * Parallel implementation using anti-diagonal wavefront pattern.
     * Each anti-diagonal k contains all cells (i, j) where i + j = k.
     * Cells on the same anti-diagonal are independent and can be computed in parallel.
     * CPL = xLength + yLength - 1 (one per anti-diagonal), Work = xLength * yLength.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {

        final int xLen = getXLength();
        final int yLen = getYLength();
        final int[][] S = getMatrix();

        // Anti-diagonal k: cells (i, j) where i + j = k, k from 2 to xLen + yLen
        // There are (xLen + yLen - 1) anti-diagonals => CPL = xLen + yLen - 1
        for (int k = 2; k <= xLen + yLen; k++) {
            final int kFinal = k;
            final int iStart = Math.max(1, k - yLen);
            final int iEnd = Math.min(xLen, k - 1);

            // All cells on anti-diagonal k are independent: compute in parallel
            finish(() -> {
                for (int i = iStart; i <= iEnd; i++) {
                    final int iF = i;
                    final int jF = kFinal - i;
                    async(() -> {
                        doWork(1);
                        final int xi = charMap(x.charAt(iF - 1));
                        final int yj = charMap(y.charAt(jF - 1));
                        S[iF][jF] = Math.max(
                            S[iF - 1][jF - 1] + getScore(xi, yj),
                            Math.max(
                                S[iF - 1][jF] + getScore(xi, 0),
                                S[iF][jF - 1] + getScore(0, yj)
                            )
                        );
                    });
                }
            });
        }

        return S[xLen][yLen];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;
import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module0.numWorkerThreads;
import static edu.rice.hj.Module1.async;

/**
 * A scorer that works in parallel with real execution time speedup.
 * Uses anti-diagonal wavefront with chunked parallelism for efficient
 * parallel execution on multi-core machines.
 */
public class UsefulParScoring extends AbstractPreallocatedSorting {

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(UsefulParScoring::new);
        scoringRunner.start("UsefulParScoring", args);
    }

    /**
     * Creates a new UsefulParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public UsefulParScoring(final int xLength, final int yLength) {
        super(xLength, yLength);
    }

    /**
     * Parallel implementation using chunked anti-diagonal wavefront.
     * Divides each anti-diagonal into numWorkerThreads chunks to reduce
     * task creation overhead while preserving parallelism.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {

        final int xLen = getXLength();
        final int yLen = getYLength();
        final int[][] S = getMatrix();
        final int numWorkers = numWorkerThreads();

        for (int k = 2; k <= xLen + yLen; k++) {
            final int kFinal = k;
            final int iStart = Math.max(1, k - yLen);
            final int iEnd = Math.min(xLen, k - 1);
            final int size = iEnd - iStart + 1;

            if (size <= numWorkers) {
                // Small diagonal: one async per cell (same as IdealParScoring)
                finish(() -> {
                    for (int i = iStart; i <= iEnd; i++) {
                        final int iF = i;
                        final int jF = kFinal - i;
                        async(() -> {
                            final int xi = charMap(x.charAt(iF - 1));
                            final int yj = charMap(y.charAt(jF - 1));
                            S[iF][jF] = Math.max(
                                S[iF - 1][jF - 1] + getScore(xi, yj),
                                Math.max(
                                    S[iF - 1][jF] + getScore(xi, 0),
                                    S[iF][jF - 1] + getScore(0, yj)
                                )
                            );
                        });
                    }
                });
            } else {
                // Large diagonal: chunk into numWorkers pieces
                final int chunkSize = (size + numWorkers - 1) / numWorkers;
                finish(() -> {
                    for (int w = 0; w < numWorkers; w++) {
                        final int chunkStart = iStart + w * chunkSize;
                        if (chunkStart > iEnd) break;
                        final int chunkEnd = Math.min(iEnd, chunkStart + chunkSize - 1);
                        async(() -> {
                            for (int i = chunkStart; i <= chunkEnd; i++) {
                                final int jF = kFinal - i;
                                final int xi = charMap(x.charAt(i - 1));
                                final int yj = charMap(y.charAt(jF - 1));
                                S[i][jF] = Math.max(
                                    S[i - 1][jF - 1] + getScore(xi, yj),
                                    Math.max(
                                        S[i - 1][jF] + getScore(xi, 0),
                                        S[i][jF - 1] + getScore(0, yj)
                                    )
                                );
                            }
                        });
                    }
                });
            }
        }

        return S[xLen][yLen];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;
import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module0.numWorkerThreads;
import static edu.rice.hj.Module1.async;

/**
 * A scorer that allocates memory during computation, so that it may compute the scores for two sequences without
 * requiring O(|X||Y|) memory.
 *
 * Uses 3 diagonal buffers (O(n) memory) with anti-diagonal wavefront parallelism.
 * diagBuffers[k % 3][i] stores S[i][k-i] for diagonal k.
 */
public class SparseParScoring extends AbstractDnaScoring {

    private final int xLength;
    private final int yLength;

    /**
     * Three rotating diagonal buffers indexed by row i.
     * diagBuffers[k % 3][i] = S[i][k-i] for valid i on anti-diagonal k.
     * Using modular indexing: needs only 3 buffers since cell (i,j) on diagonal k
     * depends only on diagonals k-1 and k-2.
     */
    private final int[][] diagBuffers;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Creates a new SparseParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
        // Each buffer indexed by row i from 0..xLength; total O(3 * xLength) = O(n)
        diagBuffers = new int[3][xLength + 1];
    }

    /**
     * Parallel sparse implementation using diagonal buffers.
     * Memory usage: O(xLength) instead of O(xLength * yLength).
     * Achieves parallelism by processing each anti-diagonal with chunked async tasks.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {

        final int numWorkers = numWorkerThreads();
        // Gap penalties for boundary conditions
        final int gapX = getScore(1, 0); // S[i][0] = i * gapX (gap in Y)
        final int gapY = getScore(0, 1); // S[0][j] = j * gapY (gap in X)

        // Process each anti-diagonal k where cells (i, j) satisfy i + j = k
        // k ranges from 2 (cell 1,1) to xLength + yLength (cell xLength, yLength)
        for (int k = 2; k <= xLength + yLength; k++) {
            final int kFinal = k;
            final int iStart = Math.max(1, k - yLength);
            final int iEnd = Math.min(xLength, k - 1);
            final int size = iEnd - iStart + 1;

            final int chunkSize = Math.max(1, (size + numWorkers - 1) / numWorkers);

            finish(() -> {
                for (int w = 0; w < numWorkers; w++) {
                    final int chunkStart = iStart + w * chunkSize;
                    if (chunkStart > iEnd) break;
                    final int chunkEnd = Math.min(iEnd, chunkStart + chunkSize - 1);

                    async(() -> {
                        for (int i = chunkStart; i <= chunkEnd; i++) {
                            final int j = kFinal - i;
                            final int xi = charMap(x.charAt(i - 1));
                            final int yj = charMap(y.charAt(j - 1));

                            // Diagonal neighbor (i-1, j-1): on diagonal k-2
                            final int valDiag;
                            if (i == 1 && j == 1) {
                                valDiag = 0; // S[0][0] = 0
                            } else if (i == 1) {
                                valDiag = (j - 1) * gapY; // S[0][j-1]
                            } else if (j == 1) {
                                valDiag = (i - 1) * gapX; // S[i-1][0]
                            } else {
                                valDiag = diagBuffers[(kFinal - 2) % 3][i - 1];
                            }

                            // Top neighbor (i-1, j): on diagonal k-1
                            final int valTop;
                            if (i == 1) {
                                valTop = j * gapY; // S[0][j]
                            } else {
                                valTop = diagBuffers[(kFinal - 1) % 3][i - 1];
                            }

                            // Left neighbor (i, j-1): on diagonal k-1
                            final int valLeft;
                            if (j == 1) {
                                valLeft = i * gapX; // S[i][0]
                            } else {
                                valLeft = diagBuffers[(kFinal - 1) % 3][i];
                            }

                            diagBuffers[kFinal % 3][i] = Math.max(
                                valDiag + getScore(xi, yj),
                                Math.max(
                                    valTop + getScore(xi, 0),
                                    valLeft + getScore(0, yj)
                                )
                            );
                        }
                    });
                }
            });
        }

        // Final answer: S[xLength][yLength] is on diagonal k = xLength + yLength
        return diagBuffers[(xLength + yLength) % 3][xLength];
    }

}

